//! antiqueue_vs_rabbit -- the receipts.
//!
//! 50k messages, 20 consumers, prefetch 1, 1ms service time. Compares:
//! * mock RabbitMQ: `Mutex<VecDeque>` per queue + `Condvar` wakeup,
//!   strict FIFO, bounded prefetch worker pool.
//! * gnosis-antiqueue: corridor-scheduled, per-consumer Stoplight, no
//!   buffer. The producer is rate-gated by the consumer's green window.
//!
//! Target: >=10x p99 message-delivery improvement, zero queue depth on
//! the antiqueue side, zero dropped messages.
//!
//! Run: `cargo bench -p gnosis-antiqueue --bench antiqueue_vs_rabbit`

use std::sync::atomic::{AtomicUsize, Ordering};
use std::sync::Arc;
use std::time::{Duration, Instant};

use divan::black_box;
use gnosis_antiqueue::mock_rabbit::read_u128_le;
use gnosis_antiqueue::{mock_rabbit, Broker, Message, Stoplight, StoplightExt};

fn main() {
    println!();
    let report = run_comparison(50_000, 20, Duration::from_millis(1));
    print_report(&report);
    print_cheap_certified_report();
    divan::main();
}

/// Head-to-head: default staggered publish vs the certified cost-aware
/// publish on a cheap-message workload. The default pays the corridor
/// stagger on every message; the certified path (RED) runs them inline.
/// This is the antiqueue receipt for the value-door crossover.
fn print_cheap_certified_report() {
    // Warm the allocator/clock first; report the second (warm) reading.
    let cold_default = run_cheap(CHEAP_TOTAL, false, Duration::from_micros(50));
    let cold_cert = run_cheap(CHEAP_TOTAL, true, Duration::from_micros(50));
    let warm_default = run_cheap(CHEAP_TOTAL, false, Duration::from_micros(50));
    let warm_cert = run_cheap(CHEAP_TOTAL, true, Duration::from_micros(50));

    let ms = |d: Duration| d.as_secs_f64() * 1000.0;
    println!("value-door certified gate (cheap-message crossover)");
    println!("====================================================");
    println!(
        "Workload: {CHEAP_TOTAL} cheap messages, 1 consumer, \
         green window offset {CHEAP_OFFSET}/{CHEAP_CYCLE} ticks, 50us tick"
    );
    println!();
    println!("  COLD:");
    println!("    default (staggered):  {:>10.2} ms", ms(cold_default));
    println!("    certified (laminar):  {:>10.2} ms", ms(cold_cert));
    println!(
        "    speedup:              {:>10.2}x",
        cold_default.as_secs_f64() / cold_cert.as_secs_f64().max(1e-9)
    );
    println!("  WARM:");
    println!("    default (staggered):  {:>10.2} ms", ms(warm_default));
    println!("    certified (laminar):  {:>10.2} ms", ms(warm_cert));
    println!(
        "    speedup:              {:>10.2}x",
        warm_default.as_secs_f64() / warm_cert.as_secs_f64().max(1e-9)
    );
    println!();
}

const SAMPLE_TOTAL: usize = 50_000;
const SAMPLE_CONSUMERS: usize = 20;
const SAMPLE_SERVICE: Duration = Duration::from_millis(1);

/// Latency percentile (raw indexing, matches the foil-runtime and
/// gnosis-frf bench convention).
fn percentile(samples: &[Duration], p: u32) -> Duration {
    if samples.is_empty() {
        return Duration::ZERO;
    }
    let mut s: Vec<Duration> = samples.to_vec();
    s.sort_unstable();
    let idx = ((p as usize) * s.len() / 100).min(s.len() - 1);
    s[idx]
}

struct Report {
    total: usize,
    consumers: usize,
    service: Duration,
    rabbit_walk: Duration,
    rabbit_p50: Duration,
    rabbit_p99: Duration,
    aq_walk: Duration,
    aq_p50: Duration,
    aq_p99: Duration,
    aq_peak: usize,
    aq_delivered: usize,
}

fn run_comparison(total: usize, consumers: usize, service: Duration) -> Report {
    let rabbit_start = Instant::now();
    let rabbit_lats = run_rabbit(total, consumers, service);
    let rabbit_walk = rabbit_start.elapsed();

    let aq_start = Instant::now();
    let (aq_lats, aq_peak, aq_delivered) = run_antiqueue(total, consumers, service);
    let aq_walk = aq_start.elapsed();

    Report {
        total,
        consumers,
        service,
        rabbit_walk,
        rabbit_p50: percentile(&rabbit_lats, 50),
        rabbit_p99: percentile(&rabbit_lats, 99),
        aq_walk,
        aq_p50: percentile(&aq_lats, 50),
        aq_p99: percentile(&aq_lats, 99),
        aq_peak,
        aq_delivered,
    }
}

fn print_report(r: &Report) {
    println!("gnosis-antiqueue vs mock RabbitMQ");
    println!("=================================");
    println!(
        "Workload: {} messages, {} consumers, prefetch=1, service={}ms",
        r.total,
        r.consumers,
        r.service.as_millis()
    );
    println!();
    println!("  Mock RabbitMQ (queue regime: Mutex+Condvar, FIFO drain)");
    println!(
        "    wall-clock:  {:>10.2} ms",
        r.rabbit_walk.as_secs_f64() * 1000.0
    );
    println!(
        "    p50 latency: {:>10.2} us",
        r.rabbit_p50.as_secs_f64() * 1_000_000.0
    );
    println!(
        "    p99 latency: {:>10.2} us",
        r.rabbit_p99.as_secs_f64() * 1_000_000.0
    );
    println!();
    println!("  gnosis-antiqueue (anti-queue regime: corridor Stoplight, no buffer)");
    println!(
        "    wall-clock:  {:>10.2} ms",
        r.aq_walk.as_secs_f64() * 1000.0
    );
    println!(
        "    p50 latency: {:>10.2} us",
        r.aq_p50.as_secs_f64() * 1_000_000.0
    );
    println!(
        "    p99 latency: {:>10.2} us",
        r.aq_p99.as_secs_f64() * 1_000_000.0
    );
    println!(
        "    peak depth:  {:>10}  (cap = consumers = {})",
        r.aq_peak, r.consumers
    );
    println!("    delivered:   {:>10}/{}", r.aq_delivered, r.total);

    let p99_speedup = r.rabbit_p99.as_nanos() as f64 / r.aq_p99.as_nanos().max(1) as f64;
    println!();
    println!("  p99 speedup:  {p99_speedup:.2}x  (target: >=10x)");
    let zero_drop = r.aq_delivered == r.total;
    println!(
        "  DoD: p99>=10x [{}], all delivered [{}], peak<=consumers [{}]",
        if p99_speedup >= 10.0 { "PASS" } else { "FAIL" },
        if zero_drop { "PASS" } else { "FAIL" },
        if r.aq_peak <= r.consumers {
            "PASS"
        } else {
            "FAIL"
        },
    );
    println!();
}

fn run_rabbit(total: usize, consumers: usize, service: Duration) -> Vec<Duration> {
    let broker = mock_rabbit::MockBroker::new();
    broker.declare_queue("tasks");
    let epoch = Instant::now();
    let b2 = Arc::clone(&broker);
    let consumer_handle =
        std::thread::spawn(move || b2.consume_blocking("tasks", consumers, service, total, epoch));
    for _ in 0..total {
        let ns = epoch.elapsed().as_nanos();
        broker.publish("tasks", Message::new("tasks", ns.to_le_bytes().to_vec()));
    }
    consumer_handle.join().unwrap()
}

fn run_antiqueue(
    total: usize,
    consumers: usize,
    service: Duration,
) -> (Vec<Duration>, usize, usize) {
    // Tick = 50us. Long enough that wait_for_tick doesn't sit in the
    // setTimeout floor; short enough that 20 corridor slots tile cleanly
    // inside a single millisecond of service work.
    let broker = Broker::with_tick(Duration::from_micros(50));
    let latencies = Arc::new(std::sync::Mutex::new(Vec::with_capacity(total)));
    let epoch = Instant::now();
    for i in 0..consumers {
        let lats = Arc::clone(&latencies);
        broker.declare_consumer(
            &format!("worker.{i}"),
            Stoplight::resting(consumers as u32, 1, ((consumers - i) % consumers) as u32),
            move |msg| {
                // Service: busy-spin.
                let svc_start = Instant::now();
                let deadline = svc_start + service;
                while Instant::now() < deadline {
                    std::hint::spin_loop();
                }
                let enq_ns = read_u128_le(&msg.body);
                let now_ns = epoch.elapsed().as_nanos();
                lats.lock().unwrap().push(Duration::from_nanos(
                    now_ns.saturating_sub(enq_ns).min(u64::MAX as u128) as u64,
                ));
                Ok(())
            },
        );
    }
    let p = broker.producer("");
    let delivered = Arc::new(AtomicUsize::new(0));
    std::thread::scope(|s| {
        let per_worker = total / consumers;
        let leftover = total - per_worker * consumers;
        for i in 0..consumers {
            let p = p.clone();
            let d = Arc::clone(&delivered);
            let count = if i == 0 {
                per_worker + leftover
            } else {
                per_worker
            };
            s.spawn(move || {
                for _ in 0..count {
                    let ns = epoch.elapsed().as_nanos();
                    if p.publish(&format!("worker.{i}"), ns.to_le_bytes().to_vec())
                        .is_ok()
                    {
                        d.fetch_add(1, Ordering::Relaxed);
                    }
                }
            });
        }
    });
    let lats = std::mem::take(&mut *latencies.lock().unwrap());
    let telemetry = broker.telemetry();
    (
        lats,
        telemetry.peak_in_flight,
        delivered.load(Ordering::Acquire),
    )
}

// ─────────────────────────────────────────────────────────────────────
// Divan bench cases (per-call samples, smaller workload for CI cost).
// ─────────────────────────────────────────────────────────────────────

#[divan::bench(sample_count = 3, sample_size = 1)]
fn rabbit_baseline(bencher: divan::Bencher) {
    bencher.bench_local(|| {
        let lats = run_rabbit(SAMPLE_TOTAL, SAMPLE_CONSUMERS, SAMPLE_SERVICE);
        black_box(lats);
    });
}

#[divan::bench(sample_count = 3, sample_size = 1)]
fn antiqueue_stoplight(bencher: divan::Bencher) {
    bencher.bench_local(|| {
        let (lats, peak, delivered) = run_antiqueue(SAMPLE_TOTAL, SAMPLE_CONSUMERS, SAMPLE_SERVICE);
        black_box((lats, peak, delivered));
    });
}

// ─────────────────────────────────────────────────────────────────────
// Value-door certified gate: cheap-message crossover.
//
// The default `publish` staggers EVERY message into its green window
// (the green-window/count gate). On CHEAP handlers the corridor stagger
// costs far more than handling the message — the antiqueue analogue of
// gnosis-frf's cheap-large over-dispatch. `publish_certified` reads the
// per-message handler cost from the consumer's QoS cert and stays laminar
// (RED, inline) when the work does not beat the gate.
//
// This case: many cheap messages to a consumer whose green window is deep
// in a long cycle. DEFAULT pays the full per-message stagger; CERTIFIED
// runs them inline. Reported by `bench_cheap_certified_speedup()` in main.
// ─────────────────────────────────────────────────────────────────────

const CHEAP_TOTAL: usize = 2_000;
/// 66-tick Grassmannian cycle; green opens at offset 60 → ~60-tick stagger.
const CHEAP_CYCLE: u32 = 66;
const CHEAP_OFFSET: u32 = 60;

/// Build a broker with one cheap-handler consumer whose green window is
/// deep in the cycle. `certified` decides which publish path is exercised.
fn run_cheap(total: usize, certified: bool, tick: Duration) -> Duration {
    let broker = Broker::with_tick(tick);
    let n = Arc::new(AtomicUsize::new(0));
    let nn = Arc::clone(&n);
    // 1ns certified handler cost: cheap. Below any ms/us-scale gate ⇒ RED.
    broker.declare_consumer_certified(
        "cheap",
        Stoplight::resting(CHEAP_CYCLE, 1, CHEAP_OFFSET),
        gnosis_antiqueue::Chirality::Compression,
        1,
        move |_| {
            // Trivial handler: a single atomic add. This is the cheap work
            // the door must not out-cost.
            nn.fetch_add(1, Ordering::Relaxed);
            Ok(())
        },
    );
    let p = broker.producer("");
    let start = Instant::now();
    for _ in 0..total {
        if certified {
            p.publish_certified("cheap", b"x".to_vec()).unwrap();
        } else {
            p.publish("cheap", b"x".to_vec()).unwrap();
        }
    }
    let elapsed = start.elapsed();
    assert_eq!(n.load(Ordering::Acquire), total);
    elapsed
}

#[divan::bench(sample_count = 5, sample_size = 1)]
fn cheap_default_staggered(bencher: divan::Bencher) {
    bencher.bench_local(|| {
        black_box(run_cheap(CHEAP_TOTAL, false, Duration::from_micros(50)));
    });
}

#[divan::bench(sample_count = 5, sample_size = 1)]
fn cheap_certified_laminar(bencher: divan::Bencher) {
    bencher.bench_local(|| {
        black_box(run_cheap(CHEAP_TOTAL, true, Duration::from_micros(50)));
    });
}
